mapper.select:
SELECT h.* FROM pr_house h
WHERE h.other_code = #{otherCode}
  AND h.is_deleted = 0

SELECT h.* FROM pr_house h
WHERE h.company_id = #{companyId}
  AND h.org_id = #{orgId}
  AND h.building_id = #{buildingId}
  AND h.is_deleted = 0
  AND h.room_num REGEXP '^[0-9]+-[0-9]+-[0-9]+$'
ORDER BY h.seq, h.room_num

mapper.update:
UPDATE pr_house
SET site_type = NULL,
    site_type_old = site_type,
    update_time = NOW()
WHERE company_id = #{companyId}
  AND org_id = #{orgId}
  AND building_id = #{buildingId}
  AND is_deleted = 0
